WITH CUSTOMER_ID_LIST AS ( SELECT MU.CORPORATION_KBN, MU.BUTEN_CODE, MU.ACCOUNT_NUMBER, MU.BROKER_CODE, MU.INTERMEDIARY_EMP_CD, MU.PHONE_NUMBER, MU.NAME_KANJI, MU.NAME_KANA, MU.ADDRESS_KANJI1, MU.TC_COMP_RANK, MU.OPEN_ACCT_DATE, MU.CUSTOMER_ID, MU.CUSTOMER_ATTRIBUTE_NAME, MU.ZIP_CODE, MU.BIRTH_DAY, MU.AGE, MU.UAI_QA_INVESTMENT_PLAN, MU.UAI_OCCUPATION, MU.UAI_QA_EMPLOYMENT_PERIOD, MU.UAI_QA_ANNUAL_INCOME, MU.UAI_QA_FINANCIAL_ASSETS, MU.UAI_QA_INCOME_FORM, MU.UAI_QA_FUND_CHARACTER, MU.UAI_EXP_STOCK_KBN, MU.UAI_EXP_DEBENTURE_KBN, MU.UAI_EXP_CB_KBN, MU.UAI_EXP_MARGIN_KBN, MU.UAI_EXP_WARRANT_KBN, MU.UAI_EXP_FUTUREOP_KBN, MU.UAI_EXP_SAVEDTYPEFUND_KBN, MU.UAI_EXP_OTHERFUND_KBN, MU.UAI_EXP_FOREIGN_KBN, MU.UAI_ISA_CONTRACT_KBN, MU.UAI_JNISA_CONTRACT_KBN, MU.UAI_EXP_STOCK, MU.UAI_EXP_DEBENTURE, MU.UAI_EXP_CB, MU.UAI_EXP_MARGIN, MU.UAI_EXP_WARRANT, MU.UAI_EXP_FUTUREOP, MU.UAI_EXP_SAVEDTYPEFUND, MU.UAI_EXP_FOREIGN, MU.UAI_EXP_OTHERFUND FROM MEDIATE_USER_ATTRIBUTE_INFO MU
WHERE 1=1 AND MU.CORPORATION_KBN = #{req.personalCorporation}
AND (
TRIM(MU.UAI_QA_INVESTMENT_PLAN) IN
#{investmentPlan}
OR
TRIM(MU.UAI_QA_INVESTMENT_PLAN) NOT IN
#{notLoggedInvestmentPlan}
OR TRIM(MU.UAI_QA_INVESTMENT_PLAN) IS NULL
)
AND (
TRIM(MU.UAI_OCCUPATION) IN
#{occupation}
OR
TRIM(MU.UAI_OCCUPATION) NOT IN
#{notLoggedOccupation}
OR TRIM(MU.UAI_OCCUPATION) IS NULL
)
AND (
TRIM(MU.UAI_QA_EMPLOYMENT_PERIOD) IN
#{employmentPeriod}
OR
TRIM(MU.UAI_QA_EMPLOYMENT_PERIOD) NOT IN
#{notLoggedEmploymentPeriod}
OR TRIM(MU.UAI_QA_EMPLOYMENT_PERIOD) IS NULL
)
AND (
TRIM(MU.UAI_QA_ANNUAL_INCOME) IN
#{annualIncome}
OR
TRIM(MU.UAI_QA_ANNUAL_INCOME) NOT IN
#{notLoggedAnnualIncome}
OR TRIM(MU.UAI_QA_ANNUAL_INCOME) IS NULL
)
AND (
TRIM(MU.UAI_QA_FINANCIAL_ASSETS) IN
#{financialAssets}
OR
TRIM(MU.UAI_QA_FINANCIAL_ASSETS) NOT IN
#{notLoggedFinancialAssets}
OR TRIM(MU.UAI_QA_FINANCIAL_ASSETS) IS NULL
)
AND (
TRIM(MU.UAI_QA_INCOME_FORM) IN
#{incomeForm}
OR
TRIM(MU.UAI_QA_INCOME_FORM) NOT IN
#{notLoggedIncomeForm}
OR TRIM(MU.UAI_QA_INCOME_FORM) IS NULL
)
AND (
TRIM(MU.UAI_QA_FUND_CHARACTER) IN
#{fundCharacter}
OR
TRIM(MU.UAI_QA_FUND_CHARACTER) NOT IN
#{notLoggedFundCharacter}
OR TRIM(MU.UAI_QA_FUND_CHARACTER) IS NULL
)
AND
MU.UAI_EXP_STOCK_KBN IN
#{stock}
MU.UAI_EXP_DEBENTURE_KBN IN
#{debenture}
MU.UAI_EXP_CB_KBN IN
#{cb}
MU.UAI_EXP_MARGIN_KBN IN
#{margin}
MU.UAI_EXP_WARRANT_KBN IN
#{warrant}
MU.UAI_EXP_FUTUREOP_KBN IN
#{futureop}
MU.UAI_EXP_SAVEDTYPEFUND_KBN IN
#{savedtypefund}
MU.UAI_EXP_OTHERFUND_KBN IN
#{other}
MU.UAI_EXP_FOREIGN_KBN IN
#{foreign}
WHERE 1=1 AND MU.CORPORATION_KBN = #{req.personalCorporation}
WHERE 1=1
AND (MU.UAI_ISA_CONTRACT_KBN = '1' OR MU.UAI_JNISA_CONTRACT_KBN = '1')
AND ((MU.UAI_ISA_CONTRACT_KBN IS NULL OR MU.UAI_ISA_CONTRACT_KBN != '1') AND (MU.UAI_JNISA_CONTRACT_KBN IS NULL OR MU.UAI_JNISA_CONTRACT_KBN != '1'))
AND MU.BUTEN_CODE = #{req.butenCode}
AND MU.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND MU.BROKER_CODE NOT IN
#{brokerCode}
AND MU.BROKER_CODE IN
#{brokerCode}
AND MU.INTERMEDIARY_EMP_CD = #{req.brokerChargeCode}
AND TRIM(MU.PHONE_NUMBER) = #{req.corporatePhoneNumber}
AND ( REGEXP_LIKE(MU.NAME_KANJI, #{req.customerNameKanjiKana}) OR REGEXP_LIKE(MU.NAME_KANA, #{req.customerNameKanjiKana}) )
AND MU.CUSTOMER_ATTRIBUTE IN
#{tradeCourse}
AND MU.ADDRESS_KANJI1 LIKE #{req.adress}
AND MU.ADDRESS_KANJI1 = #{req.adress}
AND MU.TC_COMP_RANK >= #{req.complianceLankFrom}
AND MU.TC_COMP_RANK <= #{req.complianceLankTo}
AND REPLACE(#{req.openAccountFrom}, '/') <= MU.OPEN_ACCT_DATE
AND MU.OPEN_ACCT_DATE <= REPLACE(#{req.openAccountTo}, '/')
AND 1 = 1
AND(BROKER_CODE IN
) OR BROKER_CODE IN (
,
#{brokerChargeList.brokerCode}
)
AND((BROKER_CODE, INTERMEDIARY_EMP_CD) IN
) OR (BROKER_CODE, INTERMEDIARY_EMP_CD) IN (
,
(#{brokerChargeList.brokerCode},#{brokerChargeList.empCode})
)
)
SELECT /* @SQLID=SUB0201_01-01#Sql001 */ * FROM ( SELECT count(*) over () as TOTAL_ROW , VBB.* , J.TOTAL_CURRENCT_PRICE , SDCR.VISIBLE_BUTEN_CODE , BCL.COMPLETE_DATE FROM ( SELECT M.TC_COMP_RANK , M.CUSTOMER_ATTRIBUTE_NAME , M.NAME_KANA , M.NAME_KANJI , M.OPEN_ACCT_DATE , M.ACCOUNT_NUMBER , M.ZIP_CODE , M.ADDRESS_KANJI1 , M.BROKER_CODE , M.INTERMEDIARY_EMP_CD , M.PHONE_NUMBER , M.BIRTH_DAY , M.AGE , M.BUTEN_CODE , M.BRANCH_NAME , M.BROKER_NAME /* BRANCH_NAMEをASで改称 */ , M.BROKER_CHARGE_NAME , M.BROKER_CHARGE_CODE , M.BROKER_BRANCH_CODE AS BRANCH_CODE , M.EDELIV_AGREEMENT_DATE
, E.LAST_CONTRACT_DATE
, R.PROF_LOSS_SUM , F2.ASSETS , G.COMMISSION_TOTAL , N.COMMISSION_THIS_YEAR
, CASE
WHEN SAP.FOREIGN_VIEW_INFO = '1' THEN '外国株式'
WHEN SAP.FOREIGN_VIEW_INFO = '1' THEN '米国株式（信用）'
ELSE ' ' END AS FOREIGN_VIEW_INFO
, CASE WHEN K.ERROR_COUNT_1 > 0 THEN '1' WHEN EXISTS ( SELECT * FROM MED_TRADE_RESTRICT_ERR_ACC L WHERE M.BUTEN_CODE = L.BUTEN_CODE AND M.ACCOUNT_NUMBER = L.ACCOUNT_NUMBER ) THEN '1' ELSE '0' END AS TRADE_RESTRICTION
,M.CORPORATION_KBN ,M.INVESTMENT_PLAN ,M.OCCUPATION ,M.ANNUAL_INCOME ,M.EMPLOYMENT_PERIOD ,M.FINANCIAL_ASSETS ,M.FUND_CHARACTER ,M.INCOME_FORM ,M.EXP_STOCK_KBN ,M.EXP_STOCK ,M.EXP_DEBENTURE_KBN ,M.EXP_DEBENTURE ,M.EXP_CB_KBN ,M.EXP_CB ,M.EXP_MARGIN_KBN ,M.EXP_MARGIN ,M.EXP_WARRANT_KBN ,M.EXP_WARRANT ,M.EXP_FUTUREOP_KBN ,M.EXP_FUTUREOP ,M.EXP_SAVEDTYPEFUND_KBN ,M.EXP_SAVEDTYPEFUND ,M.EXP_FOREIGN_KBN ,M.EXP_FOREIGN ,M.EXP_OTHERFUND_KBN ,M.EXP_OTHERFUND
,M.NISA_CONTRACT_VIEW_INFO
FROM ( SELECT A.CUSTOMER_ID , A.TC_COMP_RANK , A.CUSTOMER_ATTRIBUTE_NAME , A.NAME_KANA , A.NAME_KANJI , A.OPEN_ACCT_DATE , A.ACCOUNT_NUMBER , A.ZIP_CODE , A.ADDRESS_KANJI1 , A.BROKER_CODE , A.INTERMEDIARY_EMP_CD , A.PHONE_NUMBER , A.BIRTH_DAY , A.AGE , A.BUTEN_CODE , MB.BRANCH_NAME , B.BROKER_NAME , C.BROKER_CHARGE_NAME , C.BROKER_CHARGE_CODE , MCI.BROKER_BRANCH_CODE , D.EDELIV_AGREEMENT_DATE
,A.CORPORATION_KBN ,TRIM(A.UAI_QA_INVESTMENT_PLAN) AS INVESTMENT_PLAN ,TRIM(A.UAI_OCCUPATION) AS OCCUPATION ,TRIM(A.UAI_QA_ANNUAL_INCOME) AS ANNUAL_INCOME ,TRIM(A.UAI_QA_EMPLOYMENT_PERIOD) AS EMPLOYMENT_PERIOD ,TRIM(A.UAI_QA_FINANCIAL_ASSETS) AS FINANCIAL_ASSETS ,TRIM(A.UAI_QA_FUND_CHARACTER) AS FUND_CHARACTER ,TRIM(A.UAI_QA_INCOME_FORM) AS INCOME_FORM ,A.UAI_EXP_STOCK_KBN AS EXP_STOCK_KBN ,A.UAI_EXP_STOCK AS EXP_STOCK ,A.UAI_EXP_DEBENTURE_KBN AS EXP_DEBENTURE_KBN ,A.UAI_EXP_DEBENTURE AS EXP_DEBENTURE ,A.UAI_EXP_CB_KBN AS EXP_CB_KBN ,A.UAI_EXP_CB AS EXP_CB ,A.UAI_EXP_MARGIN_KBN AS EXP_MARGIN_KBN ,A.UAI_EXP_MARGIN AS EXP_MARGIN ,A.UAI_EXP_WARRANT_KBN AS EXP_WARRANT_KBN ,A.UAI_EXP_WARRANT AS EXP_WARRANT ,A.UAI_EXP_FUTUREOP_KBN AS EXP_FUTUREOP_KBN ,A.UAI_EXP_FUTUREOP AS EXP_FUTUREOP ,A.UAI_EXP_SAVEDTYPEFUND_KBN AS EXP_SAVEDTYPEFUND_KBN ,A.UAI_EXP_SAVEDTYPEFUND AS EXP_SAVEDTYPEFUND ,A.UAI_EXP_FOREIGN_KBN AS EXP_FOREIGN_KBN ,A.UAI_EXP_FOREIGN AS EXP_FOREIGN ,A.UAI_EXP_OTHERFUND_KBN AS EXP_OTHERFUND_KBN ,A.UAI_EXP_OTHERFUND AS EXP_OTHERFUND
, CASE WHEN A.UAI_ISA_CONTRACT_KBN = '1' OR A.UAI_JNISA_CONTRACT_KBN = '1' THEN '開設済' ELSE '未開設' END AS NISA_CONTRACT_VIEW_INFO
FROM CUSTOMER_ID_LIST A LEFT OUTER JOIN MEDIATE_CHARGE_INFO MCI ON A.BROKER_CODE = MCI.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = MCI.BROKER_CHARGE_CODE AND (MCI.BROKER_CODE, MCI.BROKER_CHARGE_CODE) IN ( SELECT BROKER_CODE, BROKER_CHARGE_CODE FROM MEDIATE_CHARGE_INFO MCI2 GROUP BY BROKER_CODE, BROKER_CHARGE_CODE HAVING COUNT(*) = 1 ) LEFT OUTER JOIN MEDIATE_BRANCH MB ON A.BROKER_CODE = MB.BROKER_CODE AND MCI.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE LEFT OUTER JOIN ( SELECT DISTINCT BROKER_CODE , BRANCH_NAME AS BROKER_NAME FROM MEDIATE_BRANCH WHERE BROKER_BRANCH_KIND = '00' ) B ON B.BROKER_CODE = A.BROKER_CODE LEFT OUTER JOIN ( SELECT DISTINCT BROKER_CODE , BROKER_CHARGE_CODE , BROKER_CHARGE_NAME , BROKER_BRANCH_CODE FROM MEDIATE_CHARGE_INFO WHERE BROKER_CHARGE_CODE != '0000' AND DELETE_FLG = '0' ) C ON A.BROKER_CODE = C.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = C.BROKER_CHARGE_CODE LEFT OUTER JOIN ( SELECT BUTEN_CODE , ACCOUNT_NUMBER , EDELIV_AGREEMENT_DATE FROM T_IPO_PO_EDELIV_AGRMNT WHERE EDELIV_AGREEMENT_KBN = '1' ) D ON A.ACCOUNT_NUMBER = D.ACCOUNT_NUMBER AND A.BUTEN_CODE = D.BUTEN_CODE ) M
LEFT OUTER JOIN ( SELECT DISTINCT CUSTOMER_ID , LAST_CONTRACT_DATE FROM USER_ATTRIBUTE ) E ON M.CUSTOMER_ID = E.CUSTOMER_ID
LEFT OUTER JOIN ( SELECT CUSTOMER_ID , PROF_LOSS_SUM FROM USER_PROF_LOSS_SUM ) R ON M.CUSTOMER_ID = R.CUSTOMER_ID LEFT OUTER JOIN ( SELECT DISTINCT CUSTOMER_ID, SUM(ASSETS) AS ASSETS FROM ( SELECT * FROM USER_INFO_ASSETS WHERE CUSTOMER_ID IN (SELECT CUSTOMER_ID FROM CUSTOMER_ID_LIST) ) WHERE TARGET_FLG = '07' OR TARGET_FLG = '08' GROUP BY CUSTOMER_ID ) F2 ON M.CUSTOMER_ID = F2.CUSTOMER_ID LEFT OUTER JOIN ( SELECT DISTINCT CUSTOMER_ID , SUM(NVL(COMMISSION,0)) AS COMMISSION_TOTAL FROM USER_INFO_COMMISSION WHERE 1 = 1
AND TARGET_FLG IN ('01', '02')
AND TARGET_FLG = '01'
AND TARGET_FLG = '02'
AND TARGET_FLG = '05'
AND TARGET_FLG = '07'
AND TARGET_FLG IN ('04', '10')
AND TARGET_FLG = '04'
AND TARGET_FLG = '10'
AND TARGET_FLG = '06'
AND TARGET_FLG = '08'
AND REPLACE(#{req.commTotalPeriodFrom}, '/') <= YM
AND YM <= REPLACE(#{req.commTotalPeriodTo}, '/')
AND CUSTOMER_ID IN (SELECT CUSTOMER_ID FROM CUSTOMER_ID_LIST) GROUP BY CUSTOMER_ID ) G ON M.CUSTOMER_ID = G.CUSTOMER_ID LEFT OUTER JOIN ( SELECT DISTINCT CUSTOMER_ID , SUM(NVL(COMMISSION, 0)) AS COMMISSION_THIS_YEAR FROM USER_INFO_COMMISSION WHERE YM BETWEEN TO_CHAR(SYSDATE, 'YYYY') || '01' AND TO_CHAR(SYSDATE, 'YYYYMM') AND CUSTOMER_ID IN (SELECT CUSTOMER_ID FROM CUSTOMER_ID_LIST) GROUP BY CUSTOMER_ID ) N ON M.CUSTOMER_ID = N.CUSTOMER_ID
LEFT OUTER JOIN ( SELECT ACCT_ID , CASE WHEN COUNT(ACCT_ID) > 0 THEN '1' ELSE ' ' END AS FOREIGN_VIEW_INFO
FROM ( SELECT * FROM SVC_ACCT_PROFILE_IFAP WHERE ACCT_ID IN ( SELECT BUTEN_CODE || '-' || SUBSTR('0000000' || ACCOUNT_NUMBER, -7) FROM CUSTOMER_ID_LIST )
AND PROFILE_NAME = 'TradeFStockUSPermission' AND PROFILE_VALUE = 'Yes'
AND PROFILE_NAME = 'TradeFMarginUSPermission' AND PROFILE_VALUE = 'Yes'
) GROUP BY ACCT_ID ) SAP ON M.BUTEN_CODE || '-' || SUBSTR('000000' || M.ACCOUNT_NUMBER, -7) = SAP.ACCT_ID
LEFT OUTER JOIN ( SELECT AI.CUSTOMER_ID , COUNT(*) AS ERROR_COUNT_1 FROM ( SELECT * FROM CALLCENTER.ATTENTION_INFO WHERE CUSTOMER_ID IN (SELECT CUSTOMER_ID FROM CUSTOMER_ID_LIST) AND ON_OFF_FLG = '有効' AND DELETE_TIME IS NULL ) AI INNER JOIN CALLCENTER.ATTENTION_CATEGORY_MASTER ACM ON AI.CATEGORY = ACM.CATEGORY_NAME INNER JOIN ( SELECT RESTRICT_CODE FROM M_MED_TRADE_RESTRICT WHERE RESTRICT_TYPE = '1' AND VALUE = '2' AND START_DATE <= SYSDATE AND SYSDATE <= END_DATE ) SK ON ACM.CATEGORY_CD = SK.RESTRICT_CODE GROUP BY AI.CUSTOMER_ID ) K ON M.CUSTOMER_ID = K.CUSTOMER_ID WHERE 1 = 1
AND M.BROKER_BRANCH_CODE = #{req.branchCode}
AND E.LAST_CONTRACT_DATE >= TO_DATE(#{req.lastTradeDateFrom}, 'YYYY/MM/DD')
AND E.LAST_CONTRACT_DATE <= TO_DATE(#{req.lastTradeDateTo}, 'YYYY/MM/DD') +1 - (1/86400)
AND #{req.commTotalAmountFrom} <= G.COMMISSION_TOTAL
AND G.COMMISSION_TOTAL <= #{req.commTotalAmountTo}
AND CASE WHEN REGEXP_LIKE(TRIM(M.AGE), '^\d+$') THEN TO_NUMBER(M.AGE) ELSE null END >= TO_NUMBER(#{req.ageFrom})
AND CASE WHEN REGEXP_LIKE(TRIM(M.AGE), '^\d+$') THEN TO_NUMBER(M.AGE) ELSE null END <= TO_NUMBER(#{req.ageTo})
AND REPLACE(#{req.birthDateFrom}, '/') <= M.BIRTH_DAY
AND M.BIRTH_DAY <= REPLACE(#{req.birthDateTo}, '/')
ORDER BY M.BROKER_CODE , M.BUTEN_CODE , M.ACCOUNT_NUMBER ) VBB LEFT OUTER JOIN ( SELECT ACCOUNT_NUMBER , BUTEN_CODE , SUM(CURRENCT_PRICE) AS TOTAL_CURRENCT_PRICE , SUM(
CURRENCT_PRICE
CASE WHEN PRODUT_CD = #{req.valuationConditionList} THEN CURRENCT_PRICE ELSE 0 END
) AS TOTAL_CURRENCT_PRICE_FOR_SEARCH FROM
( SELECT * FROM V_BALANCE WHERE 1 = 1
AND BUTEN_CODE = #{req.butenCode}
AND ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND (BUTEN_CODE, ACCOUNT_NUMBER) IN (SELECT BUTEN_CODE, ACCOUNT_NUMBER FROM CUSTOMER_ID_LIST) ) V_BALANCE WHERE DATE_YMD = (SELECT MAX(DATE_YMD) FROM V_BALANCE) AND PRODUT_CD IN ('01','04','06','08','09','12','13','14','15','16','25','33','50','98','99','100')
AND BUTEN_CODE = #{req.butenCode}
AND ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND BROKER_CODE NOT IN
#{brokerCode}
AND BROKER_CODE IN
#{brokerCode}
GROUP BY ACCOUNT_NUMBER , BUTEN_CODE ) J ON VBB.ACCOUNT_NUMBER = J.ACCOUNT_NUMBER AND VBB.BUTEN_CODE = J.BUTEN_CODE LEFT OUTER JOIN ( SELECT ACCOUNT_NUMBER , BUTEN_CODE , VISIBLE_BUTEN_CODE FROM SUB_DEALER_CODE_RELATION_IFAP ) SDCR ON VBB.ACCOUNT_NUMBER = SDCR.ACCOUNT_NUMBER AND VBB.BUTEN_CODE = SDCR.BUTEN_CODE LEFT OUTER JOIN ( SELECT ACCOUNT_NUMBER , BUTEN_CODE , COMPLETE_DATE FROM BROKER_CHANGE_LIST ) BCL ON VBB.ACCOUNT_NUMBER = BCL.ACCOUNT_NUMBER AND VBB.BUTEN_CODE = BCL.BUTEN_CODE WHERE 1 = 1
AND VBB.COMMISSION_TOTAL IS NOT NULL
AND VBB.FOREIGN_VIEW_INFO != ' '
AND SDCR.VISIBLE_BUTEN_CODE IN
#{butenCode}
AND BCL.COMPLETE_DATE >= REPLACE(#{req.courseChangeFinishDateFrom}, '/')
AND BCL.COMPLETE_DATE <= REPLACE(#{req.courseChangeFinishDateTo}, '/')
AND NVL(TOTAL_CURRENCT_PRICE_FOR_SEARCH, 0) >= #{req.valuationFrom}
AND NVL(TOTAL_CURRENCT_PRICE_FOR_SEARCH, 0) <= #{req.valuationTo}
AND VBB.TRADE_RESTRICTION = '1'
) WHERE 1 = 1 AND ROWNUM <= #{req.searchLimitRow} ORDER BY BROKER_CODE , BUTEN_CODE , ACCOUNT_NUMBER

SELECT /* @SQLID=SUB0201_01-01#Sql003 */
    MUAI.BUTEN_CODE AS UAI_BUTEN_CODE
  , MUAI.ACCOUNT_NUMBER AS UAI_ACCOUNT_NUMBER
  , MUAI.UAI_QA_INVESTMENT_PLAN
