  , MUAI.UAI_EXP_STOCK
  , MUAI.UAI_OFFICE_NAME
  , MUAI.UAI_QA_FINANCIAL_ASSETS
  , MUAI.CORPORATION_KBN AS UAI_CORPORATION_KBN
